import React, { useState, useEffect, useCallback } from 'react';
import Select from 'react-select';
import './CreateCombinedMaterial.css';

const LaborHoursRecord = ({
    fetchAPI,
    apiBaseUrl,
    employees
}) => {
    const [error, setError] = useState(null);
    const [projects, setProjects] = useState([]);
    const [dayRecords, setDayRecords] = useState({});

    const fetchData = useCallback(async () => {
        try {
            const projectsResponse = await fetchAPI(`${apiBaseUrl}/projectsAPI`);
    
            setProjects(projectsResponse);
    
            const initialDayRecords = {};
            employees.forEach(employee => {
                initialDayRecords[employee.name] = { employeeId: employee.empid, name: '', description: '', start: '', end: '', materials: [] };
            });
            setDayRecords(initialDayRecords);
        } catch (error) {
            console.error('Error fetching data:', error);
            setError(error.message);
        }
    }, [fetchAPI, apiBaseUrl, employees]);

    useEffect(() => {
        fetchData();
    }, [fetchData]);

    const handleChange = (employeeId, field, value) => {
        setDayRecords(prevRecords => ({
            ...prevRecords,
            [employeeId]: {
                ...prevRecords[employeeId],
                [field]: value,
            }
        }));
    };

    const handleAddMaterial = (employeeId) => {
        const newMaterial = { name: '', multiplier: 1, price: 0, sum: 0, comments: '' };
        setDayRecords(prevRecords => ({
            ...prevRecords,
            [employeeId]: {
                ...prevRecords[employeeId],
                materials: [...prevRecords[employeeId].materials, newMaterial]
            }
        }));
    };

    const handleRemoveMaterial = (employeeId, index) => {
        setDayRecords(prevRecords => ({
            ...prevRecords,
            [employeeId]: {
                ...prevRecords[employeeId],
                materials: prevRecords[employeeId].materials.filter((_, idx) => idx !== index)
            }
        }));
    };

    if (error) {
        return <div>Error: {error}</div>;
    }

    return (
        <div className="material-input-form-container">
            {Object.values(dayRecords).map((record, index) => (
                <div key={index} className="material-input-form">
                    <h3>Day Record for {record.name || `Employee ${record.employeeId}`}</h3>
                    <span className="close-popup">&times;</span>
                    <div className="form-row">
                        <div className="form-group">
                            <label htmlFor={`name-${record.employeeId}`}>Employee Name</label>
                            <input
                                id={`name-${record.employeeId}`}
                                type="text"
                                name="name"
                                value={record.name}
                                onChange={(e) => handleChange(record.employeeId, 'name', e.target.value)}
                                placeholder="Enter employee name"
                                className="form-control"
                            />
                        </div>
                        <div className="form-group">
                            <label htmlFor={`description-${record.employeeId}`}>Projects</label>
                            <textarea
                                id={`description-${record.employeeId}`}
                                name="description"
                                value={record.description}
                                onChange={(e) => handleChange(record.employeeId, 'description', e.target.value)}
                                placeholder="Enter Description"
                                className="form-control"
                            />
                        </div>
                        {/* Assume additional fields are handled similarly */}
                    </div>
                    {record.materials.map((material, matIndex) => (
                        <div key={matIndex} className="material-selection">
                            {/* Material inputs here */}
                            <button
                                onClick={() => handleRemoveMaterial(record.employeeId, matIndex)}
                                className="remove-btn">
                                Remove
                            </button>
                        </div>
                    ))}
                    <button onClick={() => handleAddMaterial(record.employeeId)} className="btn btn-primary add-btn">Add Material</button>
                    <button className="btn btn-success save-btn">Save Day Record</button>
                </div>
            ))}
        </div>
    );
};

export default LaborHoursRecord;
